sparql:
PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:party }
  UNION { ?node a gbk:gdpr-party }
  UNION { ?node a gbk:battery-party }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:protocol }
  UNION { ?node a gbk:constraint }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:obligation }
  UNION { ?node a gbk:mechanism }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:case-study }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:from ?cs . ?cs a gbk:case-study .
    ?e gb:to ?node
  }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:to ?cs . ?cs a gbk:case-study .
    ?e gb:from ?node
  }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:tension }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:from ?t . ?t a gbk:tension .
    ?e gb:to ?node
  }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:to ?t . ?t a gbk:tension .
    ?e gb:from ?node
  }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT ?node WHERE {
  { SELECT ?node (COUNT(*) AS ?c) WHERE {
    { ?e a gb:EdgeAssertion . ?e gb:from ?node }
    UNION { ?e a gb:EdgeAssertion . ?e gb:to ?node }
  } GROUP BY ?node HAVING (COUNT(*) > 3) }
}
